"""Chat response cache keyed by LLMChatRequest.cache_key."""from __future__ import annotationsimport jsonfrom dataclasses import replacefrom pathlib import Pathfrom src.core.logger import get_system_loggerfrom ..module import ModuleStorefrom ..schemas.chat import LLMChatRequest, LLMChatResponsefrom .chat_serializer import _response_from_dict as response_from_dictfrom .chat_serializer import _response_to_dict as response_to_dictdef _log():    return get_system_logger()class LLMChatRequestCache:    """    File-based chat response cache. Key is request MD5; first 3 chars = shard.    cache_path is always read from module config (ModuleStore), not passed in.    """    @staticmethod    def _shard_path(base: Path, key: str) -> Path:        """Cache file path: base/<first 3 chars of key>/<key>.json"""        return base / key[:3] / f"{key}.json"    @staticmethod    def is_cache_available() -> bool:        """True if module config has cache_path set."""        return ModuleStore.get().cache_path is not None    @staticmethod    def get(request: LLMChatRequest) -> LLMChatResponse | None:        """Return cached response or None if disabled/miss."""        path = ModuleStore.get().cache_path        if path is None:            return None        base = Path(path).resolve()        key = request.cache_key()        file_path = LLMChatRequestCache._shard_path(base, key)        if not file_path.exists():            return None        try:            data = json.loads(file_path.read_text(encoding="utf-8"))            parsed = response_from_dict(data)            return replace(parsed, cache=True)        except (json.JSONDecodeError, KeyError, TypeError) as e:            _log().warning("vision cache read failed path=%s key=%s: %s", base, key, e)            return None    @staticmethod    def set(request: LLMChatRequest, response: LLMChatResponse) -> None:        """Write response to cache: base/<shard>/<key>.json"""        path = ModuleStore.get().cache_path        if path is None:            return        base = Path(path).resolve()        base.mkdir(parents=True, exist_ok=True)        key = request.cache_key()        file_path = LLMChatRequestCache._shard_path(base, key)        file_path.parent.mkdir(parents=True, exist_ok=True)        data = response_to_dict(response)        try:            file_path.write_text(json.dumps(data, ensure_ascii=False), encoding="utf-8")        except OSError as e:            _log().warning("vision cache write failed path=%s key=%s: %s", base, key, e)            raise